#include "hip/hip_runtime.h"

#include <cmath>
#include <cstdio>

#define DIVUP(m,n) ((m) / (n) + ((m) % (n) > 0))

#define TILE_SIZE 256

// ============================================================
// Templated KNN kernel with LDS tiling + SoA + FMA
// For small K (3, 5) - keeps heap in registers
// ============================================================
template <int K>
__global__ __launch_bounds__(256)
void knn_kernel_small(int b, int n, int m,
                      const float *__restrict__ xyz,
                      const float *__restrict__ new_xyz,
                      int *__restrict__ idx,
                      float *__restrict__ dist2)
{
    __shared__ float s_x[TILE_SIZE];
    __shared__ float s_y[TILE_SIZE];
    __shared__ float s_z[TILE_SIZE];

    const int bs_idx = blockIdx.y;
    const int pt_idx = blockIdx.x * blockDim.x + threadIdx.x;

    const float *xyz_batch = xyz + bs_idx * n * 3;
    const float *new_xyz_batch = new_xyz + bs_idx * m * 3;

    float qx = 0.f, qy = 0.f, qz = 0.f;
    const bool valid = (pt_idx < m);

    if (valid) {
        qx = new_xyz_batch[pt_idx * 3 + 0];
        qy = new_xyz_batch[pt_idx * 3 + 1];
        qz = new_xyz_batch[pt_idx * 3 + 2];
    }

    float best_dist[K];
    int best_idx_arr[K];
    #pragma unroll
    for (int i = 0; i < K; i++) {
        best_dist[i] = 1e10f;
        best_idx_arr[i] = 0;
    }

    const int num_tiles = DIVUP(n, TILE_SIZE);
    for (int tile = 0; tile < num_tiles; tile++) {
        const int tile_start = tile * TILE_SIZE;
        const int tile_end = min(tile_start + TILE_SIZE, n);
        const int tile_len = tile_end - tile_start;

        for (int i = threadIdx.x; i < tile_len; i += blockDim.x) {
            const int ref_idx = tile_start + i;
            s_x[i] = xyz_batch[ref_idx * 3 + 0];
            s_y[i] = xyz_batch[ref_idx * 3 + 1];
            s_z[i] = xyz_batch[ref_idx * 3 + 2];
        }
        __syncthreads();

        if (valid) {
            for (int i = 0; i < tile_len; i++) {
                float dx = qx - s_x[i];
                float dy = qy - s_y[i];
                float dz = qz - s_z[i];
                float d2 = fmaf(dx, dx, fmaf(dy, dy, dz * dz));

                if (d2 < best_dist[0]) {
                    best_dist[0] = d2;
                    best_idx_arr[0] = tile_start + i;

                    int root = 0;
                    int child = 1;
                    while (child < K) {
                        if (child + 1 < K && best_dist[child + 1] > best_dist[child])
                            child++;
                        if (best_dist[root] >= best_dist[child]) break;
                        float td = best_dist[root]; best_dist[root] = best_dist[child]; best_dist[child] = td;
                        int ti = best_idx_arr[root]; best_idx_arr[root] = best_idx_arr[child]; best_idx_arr[child] = ti;
                        root = child;
                        child = root * 2 + 1;
                    }
                }
            }
        }
        __syncthreads();
    }

    if (!valid) return;

    for (int i = K - 1; i > 0; i--) {
        float td = best_dist[0]; best_dist[0] = best_dist[i]; best_dist[i] = td;
        int ti = best_idx_arr[0]; best_idx_arr[0] = best_idx_arr[i]; best_idx_arr[i] = ti;

        int root = 0;
        int child = 1;
        while (child < i) {
            if (child + 1 < i && best_dist[child + 1] > best_dist[child])
                child++;
            if (best_dist[root] >= best_dist[child]) break;
            float td2 = best_dist[root]; best_dist[root] = best_dist[child]; best_dist[child] = td2;
            int ti2 = best_idx_arr[root]; best_idx_arr[root] = best_idx_arr[child]; best_idx_arr[child] = ti2;
            root = child;
            child = root * 2 + 1;
        }
    }

    int *out_idx = idx + bs_idx * m * K + pt_idx * K;
    float *out_dist = dist2 + bs_idx * m * K + pt_idx * K;
    #pragma unroll
    for (int i = 0; i < K; i++) {
        out_idx[i] = best_idx_arr[i];
        out_dist[i] = best_dist[i];
    }
}

// ============================================================
// KNN kernel for larger K using LDS tiling
// Uses size-100 arrays to force scratch memory (avoids register pressure)
// Also used as generic fallback
// ============================================================
__global__ __launch_bounds__(256)
void knn_kernel_large(int b, int n, int m, int nsample,
                      const float *__restrict__ xyz,
                      const float *__restrict__ new_xyz,
                      int *__restrict__ idx,
                      float *__restrict__ dist2)
{
    __shared__ float s_x[TILE_SIZE];
    __shared__ float s_y[TILE_SIZE];
    __shared__ float s_z[TILE_SIZE];

    const int bs_idx = blockIdx.y;
    const int pt_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (bs_idx >= b || pt_idx >= m) return;

    const float *xyz_batch = xyz + bs_idx * n * 3;
    const float *new_xyz_batch = new_xyz + bs_idx * m * 3;

    float qx = new_xyz_batch[pt_idx * 3 + 0];
    float qy = new_xyz_batch[pt_idx * 3 + 1];
    float qz = new_xyz_batch[pt_idx * 3 + 2];

    // Use size 100 to force compiler to use scratch memory (like baseline)
    float best_d[100];
    int best_i[100];
    for (int i = 0; i < nsample; i++) {
        best_d[i] = 1e10f;
        best_i[i] = 0;
    }

    const int num_tiles = DIVUP(n, TILE_SIZE);
    for (int tile = 0; tile < num_tiles; tile++) {
        const int tile_start = tile * TILE_SIZE;
        const int tile_end = min(tile_start + TILE_SIZE, n);
        const int tile_len = tile_end - tile_start;

        for (int i = threadIdx.x; i < tile_len; i += blockDim.x) {
            const int ref_idx = tile_start + i;
            s_x[i] = xyz_batch[ref_idx * 3 + 0];
            s_y[i] = xyz_batch[ref_idx * 3 + 1];
            s_z[i] = xyz_batch[ref_idx * 3 + 2];
        }
        __syncthreads();

        for (int i = 0; i < tile_len; i++) {
            float dx = qx - s_x[i];
            float dy = qy - s_y[i];
            float dz = qz - s_z[i];
            float d2 = fmaf(dx, dx, fmaf(dy, dy, dz * dz));

            if (d2 < best_d[0]) {
