#include "hip/hip_runtime.h"
// Optimized three_nn kernel: float precision + fma + branchless sorting

#include <math.h>
#include <stdio.h>
#include <stdlib.h>

#define THREADS_PER_BLOCK 256
#define DIVUP(m, n) ((m) / (n) + ((m) % (n) > 0))

__global__ __launch_bounds__(256, 8)
void three_nn_kernel(int b, int n, int m,
                                const float *__restrict__ unknown,
                                const float *__restrict__ known,
                                float *__restrict__ dist2,
                                int *__restrict__ idx) {
  int bs_idx = blockIdx.y;
  int pt_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (bs_idx >= b || pt_idx >= n) return;

  const float *unk_ptr = unknown + bs_idx * n * 3 + pt_idx * 3;
  const float *known_batch = known + bs_idx * m * 3;

  float ux = unk_ptr[0];
  float uy = unk_ptr[1];
  float uz = unk_ptr[2];

  float best1 = 1e38f, best2 = 1e38f, best3 = 1e38f;
  int besti1 = 0, besti2 = 0, besti3 = 0;

  for (int k = 0; k < m; ++k) {
    float dx = ux - known_batch[k * 3];
    float dy = uy - known_batch[k * 3 + 1];
    float dz = uz - known_batch[k * 3 + 2];
    float d = __fmaf_rn(dx, dx, __fmaf_rn(dy, dy, dz * dz));

    if (d < best3) {
      // Insert d into sorted position using bubble-up with ternary ops
      // Step 1: d replaces best3
      best3 = d;
      besti3 = k;
      // Step 2: sort (best2, best3) - swap if best3 < best2
      if (best3 < best2) {
        float tmp_d = best2; int tmp_i = besti2;
        best2 = best3; besti2 = besti3;
        best3 = tmp_d; besti3 = tmp_i;
        // Step 3: sort (best1, best2) - swap if best2 < best1
        if (best2 < best1) {
          tmp_d = best1; tmp_i = besti1;
          best1 = best2; besti1 = besti2;
          best2 = tmp_d; besti2 = tmp_i;
        }
      }
    }
  }

  float *dist2_ptr = dist2 + bs_idx * n * 3 + pt_idx * 3;
  int *idx_ptr = idx + bs_idx * n * 3 + pt_idx * 3;
  dist2_ptr[0] = best1;
  dist2_ptr[1] = best2;
  dist2_ptr[2] = best3;
  idx_ptr[0] = besti1;
  idx_ptr[1] = besti2;
  idx_ptr[2] = besti3;
}

void three_nn_kernel_launcher(int b, int n, int m, const float *unknown,
                              const float *known, float *dist2, int *idx,
                              hipStream_t stream) {
  hipError_t err;
  dim3 blocks(DIVUP(n, THREADS_PER_BLOCK), b);
  dim3 threads(THREADS_PER_BLOCK);

  three_nn_kernel<<<blocks, threads, 0, stream>>>(b, n, m, unknown, known,
                                                  dist2, idx);

  err = hipGetLastError();
  if (hipSuccess != err) {
    fprintf(stderr, "CUDA kernel failed : %s\n", hipGetErrorString(err));
    exit(-1);
  }
}

