// Copyright(C) [2026] Advanced Micro Devices, Inc. All rights reserved.
#include "hip/hip_runtime.h"
#include <stdio.h>
#include <stdlib.h>
#include <ATen/ATen.h>
#include <ATen/cuda/HIPContext.h>
#include <c10/cuda/CUDAGuard.h>
#include <torch/types.h>

#include <ATen/cuda/CUDAApplyUtils.cuh>

#define TOTAL_THREADS 1024
#define THREADS_PER_BLOCK 256
#define DIVUP(m, n) ((m) / (n) + ((m) % (n) > 0))

// Optimized kernel: each thread handles one (batch, point) pair and loops over a chunk of channels.
// This amortizes the idx load while keeping enough parallelism for large C values.
// Grid: (DIVUP(M, BLOCK), DIVUP(C, CHANNELS_PER_THREAD), B), Threads: BLOCK
#define CHANNELS_PER_THREAD 8

template <typename scalar_t>
__global__ void gather_points_kernel(int b, int c, int n, int m,
                                     const scalar_t *__restrict__ points,
                                     const int *__restrict__ idx,
                                     scalar_t *__restrict__ out) {
  // points: (B, C, N)
  // idx: (B, M)
  // output:
  //      out: (B, C, M)

  int bs_idx = blockIdx.z;
  int c_start = blockIdx.y * CHANNELS_PER_THREAD;
  int pt_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (bs_idx >= b || pt_idx >= m) return;

  int idx_val = idx[bs_idx * m + pt_idx];

  const scalar_t *points_batch = points + bs_idx * c * n;
  scalar_t *out_batch = out + bs_idx * c * m;

  int c_end = c_start + CHANNELS_PER_THREAD;
  if (c_end > c) c_end = c;

  for (int c_idx = c_start; c_idx < c_end; c_idx++) {
    out_batch[c_idx * m + pt_idx] = points_batch[c_idx * n + idx_val];
  }
}

void gather_points_kernel_launcher(int b, int c, int n, int npoints,
                                   const at::Tensor& points_tensor,
                                   const at::Tensor& idx_tensor,
                                   at::Tensor& out_tensor)
{
  // points: (B, C, N)
  // idx: (B, npoints)
  // output:
  //      out: (B, C, npoints)

  hipError_t err;

  int block_size = 128;
  dim3 blocks(DIVUP(npoints, block_size), DIVUP(c, CHANNELS_PER_THREAD), b);
  dim3 threads(block_size);
  hipStream_t stream = at::cuda::getCurrentCUDAStream().stream();

  AT_DISPATCH_FLOATING_TYPES_AND_HALF(
      out_tensor.scalar_type(), "gather_points_kernel",
      [&]
       {
         const scalar_t *points = points_tensor.data_ptr<scalar_t>();
         const int *idx = idx_tensor.data_ptr<int>();
         scalar_t *out = out_tensor.data_ptr<scalar_t>();
         gather_points_kernel<<<blocks, threads, 0, stream>>>(b, c, n, npoints, points,
                                                              idx, out);
       });
  err = hipGetLastError();
  if (hipSuccess != err)
  {
    fprintf(stderr, "CUDA kernel failed : %s\n", hipGetErrorString(err));
    exit(-1);
  }
}

template <typename scalar_t>
__global__ void gather_points_grad_kernel(int b, int c, int n, int m,
                                          const scalar_t *__restrict__ grad_out,
                                          const int *__restrict__ idx,
                                          scalar_t *__restrict__ grad_points) {
  // grad_out: (B, C, M)
  // idx: (B, M)
  // output:
  //      grad_points: (B, C, N)

  int bs_idx = blockIdx.z;
  int c_idx = blockIdx.y;
  int pt_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (bs_idx >= b || c_idx >= c || pt_idx >= m) return;

  grad_out += bs_idx * c * m + c_idx * m + pt_idx;
  idx += bs_idx * m + pt_idx;
  grad_points += bs_idx * c * n + c_idx * n;

  atomicAdd(grad_points + idx[0], grad_out[0]);
}

void gather_points_grad_kernel_launcher(int b, int c, int n, int npoints,
                                        const at::Tensor& grad_out_tensor,
                                        const at::Tensor& idx_tensor,
                                        at::Tensor& grad_points_tensor)
{
  // grad_out: (B, C, npoints)
  // idx: (B, npoints)
  // output:
  //      grad_points: (B, C, N)

  hipError_t err;
  dim3 blocks(DIVUP(npoints, THREADS_PER_BLOCK), c,
              b); // blockIdx.x(col), blockIdx.y(row)
  dim3 threads(THREADS_PER_BLOCK);

  hipStream_t stream = at::cuda::getCurrentCUDAStream().stream();
  AT_DISPATCH_FLOATING_TYPES_AND_HALF(
      grad_points_tensor.scalar_type(), "gather_points_grad_kernel",
      [&]
       {
         const scalar_t *grad_out = grad_out_tensor.data_ptr<scalar_t>();
         const int *idx = idx_tensor.data_ptr<int>();
         scalar_t *grad_points = grad_points_tensor.data_ptr<scalar_t>();
         gather_points_grad_kernel<scalar_t><<<blocks, threads, 0, stream>>>(
             b, c, n, npoints, grad_out, idx, grad_points);
       });

  err = hipGetLastError();
  if (hipSuccess != err)
  {
    fprintf(stderr, "CUDA kernel failed : %s\n", hipGetErrorString(err));
    exit(-1);
  }
}

